function o(t,n="USD"){return new Intl.NumberFormat("en-US",{style:"currency",currency:n,minimumFractionDigits:2,maximumFractionDigits:2}).format(t/100)}function i(t){return t?new Date(t).toLocaleString(void 0,{year:"numeric",month:"short",day:"numeric",hour:"2-digit",minute:"2-digit"}):"—"}function u(t){if(!t)return"—";const n=new Date(t).getTime(),r=Math.round((n-Date.now())/1e3),a=Math.abs(r),e=new Intl.RelativeTimeFormat(void 0,{numeric:"auto"});return a<60?e.format(r,"second"):a<3600?e.format(Math.round(r/60),"minute"):a<86400?e.format(Math.round(r/3600),"hour"):e.format(Math.round(r/86400),"day")}export{i as a,o as f,u as r};
